const { Manifold, CrossSection, label } = api;

// Build the shield as 4 separately-labeled quarter slabs so each color
// is exactly one connected labeled piece — no fan-bleed, crisp quarter lines.
// Shield stands Z-up. Front face toward -Y.
// CrossSection is in the XY plane; extrude along Z gives depth; then rotate(90,0,0)
// maps old_Y -> new_Z (height up) and old_Z -> new_-Y (depth = front toward -Y).

const shieldH = 32;
const hw = 12;
const thickness = 3.5;
const midX = 0;
const midY = shieldH / 2; // split point for top/bottom

// Full shield outline polygon (XY plane, Y=0 bottom point, Y=shieldH top arch)
const fullPoly = [
  [0, 0],
  [hw * 0.6, shieldH * 0.2],
  [hw, shieldH * 0.5],
  [hw, shieldH * 0.85],
  [hw * 0.3, shieldH],
  [0, shieldH + 1.5],
  [-hw * 0.3, shieldH],
  [-hw, shieldH * 0.85],
  [-hw, shieldH * 0.5],
  [-hw * 0.6, shieldH * 0.2],
];

const fullCS = CrossSection.ofPolygons([fullPoly]);

// Clip boxes for each quarter (in the XY pre-rotation space)
const big = 40;
const topLeftCS = fullCS.intersect(CrossSection.square([big, big]).translate([-big, midY]));
const topRightCS = fullCS.intersect(CrossSection.square([big, big]).translate([0, midY]));
const botLeftCS = fullCS.intersect(CrossSection.square([big, big]).translate([-big, -big + midY]));
const botRightCS = fullCS.intersect(CrossSection.square([big, big]).translate([0, -big + midY]));

// Extrude each quarter then rotate to stand upright
function slab(cs) {
  return Manifold.extrude(cs, thickness).rotate([90, 0, 0]);
}

// Central boss on front face. Front face in world coords is at Y=0, protrudes in -Y.
// Boss center slightly proud of face; overlaps into shield face by 0.5+ units.
const bossR = 2.8;
const bossZ = shieldH / 2 + 2; // world Z = mid-height of shield + a bit
const boss = Manifold.sphere(bossR, 32).translate([0, -bossR * 0.35, bossZ]);

const qTL = label(slab(topLeftCS), 'red'); // top-left: RED
const qTR = label(slab(topRightCS), 'blue'); // top-right: BLUE
const qBL = label(slab(botLeftCS), 'gold'); // bottom-left: GOLD
const qBR = label(slab(botRightCS), 'silver'); // bottom-right: SILVER
const bossL = label(boss, 'boss');

return qTL.add(qTR).add(qBL).add(qBR).add(bossL);
